import{_ as a,c as s,a1 as t,o as n}from"./chunks/framework.BDxlaA_J.js";const h=JSON.parse('{"title":"Open Source Intelligence Gathering using OSRFramework","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/4-OSRFramework.md","filePath":"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/4-OSRFramework.md"}'),i={name:"categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/4-OSRFramework.md"};function r(o,e,c,l,p,d){return n(),s("div",null,e[0]||(e[0]=[t(`<h1 id="open-source-intelligence-gathering-using-osrframework" tabindex="-1">Open Source Intelligence Gathering using OSRFramework <a class="header-anchor" href="#open-source-intelligence-gathering-using-osrframework" aria-label="Permalink to &quot;Open Source Intelligence Gathering using OSRFramework&quot;">​</a></h1><p>OSRFramework is a set of libraries to perform Open Source Intelligence tasks. They include references to a bunch different applications related to username checking, DNS lookups, information leaks research, deep web search, regular expressions extraction, and many others.</p><h3 id="objectives" tabindex="-1">Objectives: <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives:&quot;">​</a></h3><ul><li>Demonstrate how to identify usernames of the target on different social media platforms.</li></ul><h3 id="requirements" tabindex="-1">Requirements: <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements:&quot;">​</a></h3><ul><li>Kali Linux virtual machine.</li></ul><hr><ol><li><p>Log into <strong>Kali Linux</strong> machine and open a <strong>Terminal</strong> window..</p></li><li><p>Update APT and install the OSRFramework:</p></li></ol><p><code>apt update &amp;&amp; apt -y install osrframework</code></p><h2 id="using-usufy-py" tabindex="-1">Using usufy.py <a class="header-anchor" href="#using-usufy-py" aria-label="Permalink to &quot;Using usufy.py&quot;">​</a></h2><p><code>usufy.py</code> checks for the existence of a profile for a given user details in different platforms.</p><p>Usage: <strong>usufy.py -n <code>target</code> -p twitter facebook youtube</strong></p><p><code>usufy.py -n cehuser us -p twitter facebook youtube</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+-----------------------------+---------------+------------------+</span></span>
<span class="line"><span>|         i3visio_uri         | i3visio_alias | i3visio_platform |</span></span>
<span class="line"><span>+=============================+===============+==================+</span></span>
<span class="line"><span>| \`http://twitter.com/us\`       | us            | Twitter          |</span></span>
<span class="line"><span>+-----------------------------+---------------+------------------+</span></span>
<span class="line"><span>| \`https://www.facebook.com/us\` | us            | Facebook         |</span></span>
<span class="line"><span>+-----------------------------+---------------+------------------+</span></span>
<span class="line"><span>| \`http://twitter.com/cehuser\`  | cehuser       | Twitter          |</span></span>
<span class="line"><span>+-----------------------------+---------------+------------------+</span></span></code></pre></div><p>The <strong>usufy.py</strong> will search the user details in the mentioned platform and will provide you with existence of the user as shown above.</p><h2 id="using-searchfy-py" tabindex="-1">Using searchfy.py <a class="header-anchor" href="#using-searchfy-py" aria-label="Permalink to &quot;Using searchfy.py&quot;">​</a></h2><p><code>searchfy.py</code> checks with the existing users of pages/handlers for a given details in the all social networks.</p><p>Usage: <code>searchfy.py -q &quot;Page Name or Handler Name&quot;</code></p><p><code>searchfy.py -q &quot;ECCouncil&quot;</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/c07e9574a732bbd239c81d4b1e24bee3de20e62b/searchfy-eccouncil.png" alt="alt text" title="serachfy eccouncil screenshot"></p><p>It will pull out all the user details who are subscribed to targeted social networking pages that are provided.</p><h2 id="osrframework-cli-subcommands" tabindex="-1">OSRFramework CLI subcommands: <a class="header-anchor" href="#osrframework-cli-subcommands" aria-label="Permalink to &quot;OSRFramework CLI subcommands:&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Subcommands</th><th>Description</th></tr></thead><tbody><tr><td>usufy.py</td><td>This tool that verifies if a username exists in 249 social platforms.</td></tr><tr><td>mailfy.py</td><td>This module checks if a username has been registered in up to 22 email providers.</td></tr><tr><td>searchfy.py</td><td>This module looks for profiles using full names and other info in 7 platforms.</td></tr><tr><td>domainfy.py</td><td>This module checks the existence of a given domain in up to 879 different TLD.</td></tr><tr><td>phonefy.py</td><td>This module checks if a phone number has been linked to spam practices in 4 platforms.</td></tr><tr><td>entify.py</td><td>This module looks for regular expressions using 13 patterns.</td></tr></tbody></table>`,23)]))}const m=a(i,[["render",r]]);export{h as __pageData,m as default};
